 1	import * as React from 'react';
 2	import Linkify from 'react-linkify';
 3	import { Button, Icon } from '@patternfly/react-core';
 4	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
 5	
 6	export const ExternalLink: React.FC<ExternalLinkProps> = ({
 7	  children,
 8	  href,
 9	  text,
10	  additionalClassName = '',
11	  dataTestID,
12	  stopPropagation,
13	}) => (
14	  <Button
15	    variant="link"
16	    component="a"
17	    icon={
18	      <Icon size="sm">
19	        <ExternalLinkAltIcon />
20	      </Icon>
21	    }
22	    className={additionalClassName}
23	    href={href}
24	    target="_blank"
25	    iconPosition="end"
26	    rel="noopener noreferrer"
27	    data-test-id={dataTestID}
28	    {...(stopPropagation ? { onClick: (e) => e.stopPropagation() } : {})}
29	    isInline
30	  >
31	    {children || text}
32	  </Button>
33	);
34	
35	// Open links in a new window and set noopener/noreferrer.
36	export const LinkifyExternal: React.FC<{ children: React.ReactNode }> = ({ children }) => (
37	  <Linkify properties={{ target: '_blank', rel: 'noopener noreferrer' }}>{children}</Linkify>
38	);
39	LinkifyExternal.displayName = 'LinkifyExternal';
40	
41	type ExternalLinkProps = {
42	  href: string;
43	  text?: React.ReactNode;
44	  additionalClassName?: string;
45	  dataTestID?: string;
46	  stopPropagation?: boolean;
47	};

